    /// </summary>
    public async Task<PurchaseResult> PurchaseTicketsAsync(
        int eventId,
        string customerId,
        int quantity,
        string idempotencyKey)
    {
        if (quantity <= 0 || quantity > MaxTicketsPerPurchase)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = $"Quantity must be between 1 and {MaxTicketsPerPurchase}."
            };
        }

        if (string.IsNullOrWhiteSpace(customerId))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Customer ID is required."
            };
        }

        if (string.IsNullOrWhiteSpace(idempotencyKey))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Idempotency key is required to prevent duplicate purchases."
            };
        }

        // Check for an existing purchase with the same idempotency key (replay protection)
        var existingPurchase = await _dbContext.TicketPurchases
            .AsNoTracking()
            .FirstOrDefaultAsync(tp => tp.IdempotencyKey == idempotencyKey);

        if (existingPurchase != null)
        {
            return new PurchaseResult
            {
                Success = true,
                Message = "Purchase already completed (idempotent replay).",
                PurchaseId = existingPurchase.PurchaseId
            };
        }

        for (int attempt = 0; attempt < MaxRetries; attempt++)
        {
            try
            {
                var result = await AttemptPurchaseAsync(eventId, customerId, quantity, idempotencyKey);
                return result;
            }
            catch (DbUpdateConcurrencyException)
            {
                // Another concurrent transaction modified the row; detach tracked entities and retry
                foreach (var entry in _dbContext.ChangeTracker.Entries())
