    private async Task<PurchaseResult> AttemptPurchaseAsync(
        int eventId,
        string customerId,
        int quantity,
        string idempotencyKey)
    {
        // Use a serializable transaction + optimistic concurrency (RowVersion) for maximum safety.
        // The RowVersion check ensures that if two transactions read the same row,
        // only one can successfully update it.
        await using var transaction = await _dbContext.Database
            .BeginTransactionAsync(System.Data.IsolationLevel.Serializable);

        try
        {
            // Load the event entity — EF Core will track the RowVersion
            var eventEntity = await _dbContext.Events
                .FirstOrDefaultAsync(e => e.EventId == eventId);

            if (eventEntity == null)
            {
                await transaction.RollbackAsync();
                return new PurchaseResult
                {
                    Success = false,
                    Message = "Event not found."
                };
            }

            // Validate available seats — this check is protected by both the
            // serializable isolation level AND the RowVersion optimistic concurrency token.
            if (eventEntity.AvailableSeats < quantity)
            {
                await transaction.RollbackAsync();
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"Not enough seats available. Only {eventEntity.AvailableSeats} remaining."
                };
            }

            // Atomically decrement available seats
            // The RowVersion column ensures this UPDATE will fail with DbUpdateConcurrencyException
            // if another transaction modified the row between our SELECT and UPDATE.
            eventEntity.AvailableSeats -= quantity;

            // Create the purchase record with idempotency key
            var purchase = new TicketPurchase
            {
                EventId = eventId,
                CustomerId = customerId,
                Quantity = quantity,
                PurchasedAt = DateTime.UtcNow,
                IdempotencyKey = idempotencyKey
