            _dbContext.TicketPurchases.Add(purchase);

            // SaveChanges will include the WHERE RowVersion = @originalVersion clause
            // on the Event UPDATE, providing optimistic concurrency protection
            await _dbContext.SaveChangesAsync();
            await transaction.CommitAsync();

            return new PurchaseResult
            {
                Success = true,
                Message = $"Successfully purchased {quantity} ticket(s).",
                PurchaseId = purchase.PurchaseId
            };
        }
        catch
        {
            await transaction.RollbackAsync();
            throw;
        }
    }

